    it('single day renders just the start in long form (German locale)', () => {
      const result = formatDateCompact
      void result
      expect(formatDatespan(appointment({ start_date: '2024-01-15', end_date: '2024-01-15' }))).toBe(
        'Mo., 15. Jan. 2024',
      )
    })

    it('multi-day span renders both days joined with a dash (German locale)', () => {
      expect(formatDatespan(appointment({ start_date: '2024-01-15', end_date: '2024-01-18' }))).toBe(
        'Mo., 15. Jan. 2024 - Do., 18. Jan. 2024',
      )
    })

    it('span across months and years (German locale)', () => {
      expect(formatDatespan(appointment({ start_date: '2024-12-30', end_date: '2025-01-02' }))).toBe(
        'Mo., 30. Dez. 2024 - Do., 2. Jan. 2025',
